import React from "react"
import '../collapse.css'
import FullCalendar from '@fullcalendar/react' // must go before plugins
import dayGridPlugin from '@fullcalendar/daygrid' // a plugin!
import interactionPlugin from "@fullcalendar/interaction" // needed for dayClick
import Moment from 'moment'
import Collapsible from "react-collapsible"
import { properties } from '../../properties/properties.js'

var evalValue = []
//var checkedEval = []
var buildEvaluation = []
var indexCheckbox = 0

class Scheduler extends React.Component {


    constructor(props) {
        super(props);
        this.state = {
            results: [], teamValue: "", screen: 0, dateStr: "", teamId: "", incompleteEval: [], createEvalResult: [], disableSubmitButton: true, statusEval: [], setCalendarDate: ""
        };

    }



      callRefreshData() {
        let headers = new Headers();

        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');

        var backUrl = properties.backend + `scheduler/get_schedule`

        fetch(backUrl, {
            "method": "GET",
            headers: headers
          })
          .then(response => response.json())
          .then(response => {
            //console.log(response);
            this.setState({results: response})
            //this.setState({screen: 1})
            //_forEach(response, d => console.log(d.name))
            //console.log(this.state.results)

            var evalResult = this.state.results.filter(Record => Record.eventDate === this.state.dateStr)[0].evalResult

            //if (response.result.error === "") {
              //evalResult.push(response.requestObject)
            //}

            var dateTeam = this.state.results.filter(Record => Record.eventDate === this.state.dateStr)[0].data.filter(Record => Record.id === this.state.teamId)[0]

            //console.log(dateTeam)

            var userIDs = []
            if (dateTeam.userID != 0) {
              userIDs.push(dateTeam.userID)
            }

            for (let y in dateTeam.members) {
              if (dateTeam.members[y].userID != 0){
                userIDs.push(dateTeam.members[y].userID)
              }
            }

            var evalResult2 = []
            for (let i in userIDs) {
              for (let j in evalResult) {
                if (evalResult[j].evaluator_userID === userIDs[i]) {
                  evalResult2.push(evalResult[j])
                }
              }
            }

            //console.log(evalResult2)

            if (evalResult2.length > 0) {
              //this.callStatus(evalResult, 3)
              this.setState({screen: 3})
            } else {
              this.setState({screen: 3})
            }




          })
          .catch(err => {
            console.log(err);
          });

      }


        componentDidMount() {


          this.setState({setCalendarDate: Moment().format("YYYY-MM-DD")})


          //console.log(Moment().format("YYYY-MM-DD"))

            let headers = new Headers();

            headers.append('Content-Type', 'application/json');
            headers.append('Accept', 'application/json');

            var backUrl = properties.backend + `scheduler/get_schedule`

            fetch(backUrl, {
                "method": "GET",
                headers: headers
              })
              .then(response => response.json())
              .then(response => {
                //console.log(response);
                this.setState({results: response})
                this.setState({screen: 1})
                //_forEach(response, d => console.log(d.name))
                //console.log(this.state.results)
              })
              .catch(err => {
                console.log(err);
              });


          }


          handleDidMount = () => {

            for (let x in this.state.results) {
              var inTomorrow = true
              //content.push(<div>{this.state.results[x].eventDate}</div>)
              //content.push(<div><hr></hr></div>)
              //each team


              for (let y in this.state.results[x].data) {
                  if (!this.state.results[x].data[y].inTomorrow) {
                    inTomorrow = false
                  }
                  for (let z in this.state.results[x].data[y].members) {
                    if (!this.state.results[x].data[y].members[z].inTomorrow) {
                        inTomorrow = false
                    }
                  }
              } 

              var coloring = "blue"

              if (!inTomorrow) {
                /*
                if (findDate != null) {
                  var dateNumber = findDate.getElementsByClassName("fc-daygrid-day-number")
                  for (var i = 0; i < dateNumber.length; i++) {
                    dateNumber[i].style.color = "red"; 
                  }
                }
                */
               coloring = "red"

              }

              var findDate = document.querySelector('[data-date="' + this.state.results[x].eventDate +'"]')
              if (findDate != null) {
                var dateNumber = findDate.getElementsByClassName("fc-daygrid-day-number")
                for (var i = 0; i < dateNumber.length; i++) {
                  dateNumber[i].style.color = coloring; 
                  dateNumber[i].style.fontWeight = "bold";
                }
              }



            }



          }





          handleEventClick = (arg) => { // bind with an arrow function



              this.setState({dateStr: arg.event.startStr})


              this.setState({setCalendarDate: arg.event.startStr})

              this.setState({screen: 0})

              //var evalResult = this.state.results.filter(Record => Record.eventDate === arg.event.startStr)[0].evalResult

              //console.log(dateTeam)
              //this.callStatus(evalResult, 4)
              this.setState({screen: 4})

            //}

          }





          handleDateClick = (arg) => { // bind with an arrow function


                  if (this.state.results.filter(Record => Record.eventDate === arg.dateStr).length > 0) {
                    this.setState({dateStr: arg.dateStr})
                    this.setState({setCalendarDate: arg.dateStr})

                    this.setState({screen: 0})

                    try {

                      //console.log(dateTeam)
                      //this.callStatus(evalResult, 4)

                      this.setState({screen: 4})


                    } catch (e) {
                      this.setState({screen: 4})
                    }
                  } else {
                    alert("Data is not avaliable")
                  }




          }


          goBackFirstScreen = () => {
            this.setState({screen: 1});
          }

          goBackSecondScreen = () => {




            this.setState({screen: 4});
          }

          goBack = (showIncomplete) => {



            if (this.state.results.filter(Record => Record.eventDate === Moment(this.state.dateStr, "YYYY-MM-DD").add(-1, 'days').format("YYYY-MM-DD")).length > 0) {

              this.setState({dateStr: Moment(this.state.dateStr, "YYYY-MM-DD").add(-1, 'days').format("YYYY-MM-DD")})
              //console.log(Moment(this.state.dateStr, "YYYY-MM-DD").add(1, 'days').format("YYYY-MM-DD"))
              //this.setState({screen: 2})
              this.setState({screen: 0})


              if (showIncomplete) {

                var dateTeam = this.state.results.filter(Record => Record.eventDate === Moment(this.state.dateStr, "YYYY-MM-DD").add(-1, 'days').format("YYYY-MM-DD"))[0].data

                  var userIDs = []
                  for (let x in dateTeam) {
                    if (dateTeam[x].userID != 0) {
                      userIDs.push(dateTeam[x].userID)
                    }

                    for (let y in dateTeam[x].members) {
                      if (dateTeam[x].members[y].userID != 0){
                        userIDs.push(dateTeam[x].members[y].userID)
                      }
                    }
                  }


                this.callIncomplete(userIDs, 2)
              } else {

                //var evalResult = this.state.results.filter(Record => Record.eventDate === Moment(this.state.dateStr, "YYYY-MM-DD").add(-1, 'days').format("YYYY-MM-DD"))[0].evalResult

                //console.log(dateTeam)
                //this.callStatus(evalResult, 4)
                this.setState({screen: 4})

              }
            } else {
              alert("Data is not avaliable")
            }

          }


          goForward = (showIncomplete) => {




            if (this.state.results.filter(Record => Record.eventDate === Moment(this.state.dateStr, "YYYY-MM-DD").add(1, 'days').format("YYYY-MM-DD")).length > 0) {
              this.setState({dateStr: Moment(this.state.dateStr, "YYYY-MM-DD").add(1, 'days').format("YYYY-MM-DD")})
              //this.setState({screen: 2})
              this.setState({screen: 0})


              if (showIncomplete) {

                var dateTeam = this.state.results.filter(Record => Record.eventDate === Moment(this.state.dateStr, "YYYY-MM-DD").add(1, 'days').format("YYYY-MM-DD"))[0].data

                  var userIDs = []
                  for (let x in dateTeam) {
                    if (dateTeam[x].userID != 0) {
                      userIDs.push(dateTeam[x].userID)
                    }

                    for (let y in dateTeam[x].members) {
                      if (dateTeam[x].members[y].userID != 0){
                        userIDs.push(dateTeam[x].members[y].userID)
                      }
                    }
                  }


                this.callIncomplete(userIDs, 2)
              } else {

                //var evalResult = this.state.results.filter(Record => Record.eventDate === Moment(this.state.dateStr, "YYYY-MM-DD").add(1, 'days').format("YYYY-MM-DD"))[0].evalResult

                //console.log(dateTeam)
                //this.callStatus(evalResult, 4)
                this.setState({screen: 4})

              }
            } else {
              alert("Data is not available")
            }

          }


          goCreateEvaluation = (teamId) => {
            this.setState({screen: 0})
            this.setState({teamId: teamId})
            this.setState({createEvalResult: []})


            var evalResult = this.state.results.filter(Record => Record.eventDate === this.state.dateStr)[0].evalResult
            var dateTeam = this.state.results.filter(Record => Record.eventDate === this.state.dateStr)[0].data.filter(Record => Record.id === teamId)[0]

            //console.log(dateTeam)

            var userIDs = []
            if (dateTeam.userID != 0) {
              userIDs.push(dateTeam.userID)
            }

            for (let y in dateTeam.members) {
              if (dateTeam.members[y].userID != 0){
                userIDs.push(dateTeam.members[y].userID)
              }
            }

            var evalResult2 = []
            for (let i in userIDs) {
              for (let j in evalResult) {
                if (evalResult[j].evaluator_userID === userIDs[i]) {
                  evalResult2.push(evalResult[j])
                }
              }
            }




            //console.log(evalResult2)

            if (evalResult2.length > 0) {
              //this.callStatus(evalResult, 3)
              this.setState({screen: 3})
            } else {
              this.setState({screen: 3})
            }
            //console.log(dateTeam)
            //this.callStatus(evalResult)




/*
            this.callIncomplete(userIDs, 3)
*/





          }


          handleOnChange = (checkboxID) => {

            //console.log(document.getElementById("123").value.evaluationID)
           //document.getElementById("submitButton").disabled = false

            var noSelect = true
            var i = 0
            while (i < indexCheckbox) {
              //console.log(document.getElementById("eval"+i).checked)
              if (document.getElementById("eval"+i).checked) {
                noSelect = false
              }
              i += 1
            }


            this.setState({disableSubmitButton: noSelect})
            //console.log(evalValue)
          }

          handleSubmitEval = () => {

            //console.log(evalValue)
            var buildRequest = []
            var i = 0
            while (i < indexCheckbox) {
              //console.log(document.getElementById("eval"+i).checked)
              if (document.getElementById("eval"+i).checked) {
                var evalValueModified = evalValue.filter(Record => Record.checkboxID === i)[0]
                evalValueModified.forDate = this.state.dateStr
                buildRequest.push(evalValueModified)
              }
              i += 1
            }
            this.createEval(buildRequest)
           //console.log(buildRequest)

            //console.log("submit")
          }


          makeCheckBox = (evaluator,evaluatee,evalId,evalType,evaluator_userID,evaluatee_userID,title,rotationStart,rotationEnd) => {

            if (evaluator_userID != 0 && evaluatee_userID != 0) {
              var checkboxValue = {"evaluator":evaluator,"evaluatee":evaluatee,"checkboxID": indexCheckbox,"evaluationID":evalId,"eval_type":evalType,"evaluator_userID":evaluator_userID,"programID":1350,"evaluatee_userID":evaluatee_userID,"title":title,"rotationStart":rotationStart,"rotationEnd":rotationEnd}
              evalValue.push(checkboxValue)
              var checkboxID = "eval" + indexCheckbox
            //checkedEval.push(indexCheckbox)
              indexCheckbox += 1

              buildEvaluation.push(<div><input onChange={() => this.handleOnChange(indexCheckbox)} id={checkboxID} type="checkbox"/><label>{title}</label></div>)
            } else {
              var errorMsg = ""
              if (evaluator_userID === 0) {
                errorMsg += evaluator + " doesn't have medhubID"
              }
              if (evaluatee_userID === 0) {
                errorMsg += evaluatee + " doesn't have medhubID"
              }
              buildEvaluation.push(<div><label style={{color: "red"}}>{title} - {errorMsg}</label></div>)
            }

            //console.log(evalValue)

          }






          render() {


            var todayDate = "Loading ..."
            var content = []
            var events = []

            var overLapDayFilter = 5



            if (this.state.screen === 1) {

              todayDate = ""
              for (let x in this.state.results) {
                var inTomorrow = true 
                for (let y in this.state.results[x].data) {
                  if (!this.state.results[x].data[y].inTomorrow) {
                    inTomorrow = false
                  }
                  for (let z in this.state.results[x].data[y].members) {
                    if (!this.state.results[x].data[y].members[z].inTomorrow) {
                      inTomorrow = false
                    }
                  }
                }
                if (!inTomorrow) {
                  events.push({id: "", groupId: this.state.results[x].groupId,title: " - Rotation Change - ",  date: this.state.results[x].eventDate, color: "#FF7F7F", textColor: "black" })
                }

              }


              content.push(                 <FullCalendar
                plugins={[ dayGridPlugin, interactionPlugin ]}
                initialView="dayGridMonth"
                events={events}
                eventClick={this.handleEventClick}
                dateClick={this.handleDateClick}
                eventOrder="id"
                eventDidMount={this.handleDidMount}
                initialDate= {this.state.setCalendarDate}
                //navLinkDayClick={this.handleLinkClick}

              />)



            }


            if (this.state.screen === 3) {
              todayDate = ""
              var dateTeam = this.state.results.filter(Record => Record.eventDate === this.state.dateStr)[0].data.filter(Record => Record.id === this.state.teamId)[0]
              //console.log(dateTeam)
              content.push(<div> <button onClick={() => this.goBackSecondScreen()} style={{height: "30px", width: "120px", fontSize: "16px", backgroundColor: "yellow"}}>Go Back</button><h3>Date: {dateTeam.date}</h3></div>)

              content.push(<div style={{color: "green", marginBottom: "5px", fontStyle: "bold"}}><h3>{dateTeam.assignment}</h3></div>)
              content.push(<hr></hr>)
              content.push(<div></div>)

              buildEvaluation = []


              var facuColor = "black"
              if (!dateTeam.inTomorrow) {
                facuColor = "red"
              }


              var residentsContent = []
              evalValue = []

              indexCheckbox = 0

              for (let y in dateTeam.members) {

                var colorRes = "black"
                if (!dateTeam.members[y].inTomorrow) {
                  colorRes = "red"
                }


                //residentsContent.push(<div style={{marginLeft: '10px', color: colorRes}}>- {dateTeam.members[y].name} * medHubID: ({dateTeam.members[y].userID}) - programID: {dateTeam.members[y].programID}</div>)

                var noEval = true
                var addResInternToFacultyEval = false

                var typeString = ""

                var createCheckbox = dateTeam.members[y].overlap.filter(Record => Record.name === dateTeam.name)[0].daysTogether >= overLapDayFilter && dateTeam.members[y].programID != "1275"

                if (dateTeam.members[y].resident) {
                  typeString = " - resident"
                  if (!dateTeam.inTomorrow || !dateTeam.members[y].inTomorrow) {
                    if (createCheckbox) {
                      this.makeCheckBox(dateTeam.name,dateTeam.members[y].name,5735,5,dateTeam.userID,dateTeam.members[y].userID,dateTeam.name + " => " + dateTeam.members[y].name + " * IM - UC Wards (Faculty of Resident - New)",dateTeam.members[y].rotationStart,dateTeam.members[y].rotationEnd)
                    }
                    addResInternToFacultyEval = true
                  } 
                }
                if (dateTeam.members[y].intern) {
                  typeString = " - intern"
                  if (!dateTeam.inTomorrow || !dateTeam.members[y].inTomorrow) {
                    if (createCheckbox) {
                      this.makeCheckBox(dateTeam.name,dateTeam.members[y].name,5734,5,dateTeam.userID,dateTeam.members[y].userID,dateTeam.name + " => " + dateTeam.members[y].name + " * IM - UC Wards (Faculty of Intern - New)",dateTeam.members[y].rotationStart,dateTeam.members[y].rotationEnd)
                    }
                    addResInternToFacultyEval = true
                  }
                }

                if (addResInternToFacultyEval) {
                  if (createCheckbox) {
